var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":["stopWordFilter"]},"docs":[{"location":"Overview.html","title":"\ud83d\udc4b Welcome to ATIDocs","text":"<p>ATIDocs is your developer-friendly, Doom One\u2013themed documentation hub \u2014 focused on everything from frontend frameworks to backend systems, DevOps, algorithms, patterns, and more.</p> <p>\ud83d\ude80 Whether you're:</p> <ul> <li>A frontend dev learning React or Vue,</li> <li>A backend engineer digging into APIs or databases,</li> <li>Or just browsing cool coding patterns...</li> </ul> <p>This is your place.</p>"},{"location":"Overview.html#keyboard-navigation","title":"\ud83d\udd79\ufe0f Keyboard Navigation","text":"<p>Navigate this site without touching your mouse:</p> <ul> <li>H / J / K / L \u2014 Move <code>left</code>/<code>down</code>/<code>up</code>/<code>right</code> like in Vim</li> <li>G <code>+</code> G \u2014 Jump to the <code>top</code> of the page</li> <li>Shift <code>+</code> G \u2014 Jump to the <code>bottom</code></li> <li>F \u2014 Activate <code>hint mode</code> to follow links instantly</li> </ul> <p>\u26a1 This experience is powered by vimium and browser extensions integrated into ATIDocs.</p>"},{"location":"Overview.html#sections","title":"\ud83d\udcda Sections","text":"<ul> <li>\ud83e\udde0 Frontend: JavaScript, React, TypeScript, Vue, Next.js &amp; more</li> <li>\u2699\ufe0f Backend: Node.js, Express, GraphQL, REST, Databases</li> <li>\ud83d\udd27 DevOps: Docker, CI/CD, Nginx</li> <li>\ud83e\uddea Testing: Jest, Vitest</li> <li>\ud83d\udcca Algorithms &amp; Patterns</li> <li>\u2702\ufe0f Snippets &amp; Notes</li> <li>\ud83d\udcbb Languages</li> </ul>"},{"location":"Overview.html#get-started","title":"\ud83d\udccc Get Started","text":"<p>Check out the Frontend Overview or jump into a topic from the sidebar.</p>"},{"location":"about.html","title":"\ud83d\ude4b About ATIDocs","text":"<ul> <li>ATIDocs is a curated and themed developer documentation project maintained by:   Mohamed Attia.</li> </ul>"},{"location":"about.html#why","title":"\u2728 Why?","text":"<p>In the sea of tutorials, docs, and blog posts, ATIDocs aims to be a:</p> <ul> <li>\ud83e\udded Structured guide</li> <li>\ud83c\udf17 Aesthetic experience</li> <li>\ud83d\udee0\ufe0f Tool for learning, reference, and sharing</li> </ul> <p>Inspired by the Doom One theme, powered by MkDocs Material, and built for developers who love clean docs.</p>"},{"location":"about.html#tech-stack","title":"\ud83d\udd27 Tech Stack","text":"<ul> <li>MkDocs + Material for MkDocs</li> <li>Python for build tooling</li> <li>GitHub Pages / static hosting</li> </ul>"},{"location":"about.html#clone-use-this-project","title":"\ud83d\udee0\ufe0f Clone &amp; Use This Project","text":"<p>This project is open source and publicly available \u2014 feel free to explore, learn, and reuse it for your own documentation needs!</p> <p>You can clone it from GitHub:</p> <pre><code>git clone https://github.com/Mohamedattiadev/AtiDocs.git\n</code></pre>"},{"location":"contact.html","title":"\ud83d\udcec Contact","text":"<ul> <li>Want to reach out, collaborate, or contribute?</li> </ul>"},{"location":"contact.html#community-discussions","title":"\ud83e\udde0 Community &amp; Discussions","text":"<ul> <li>Start a GitHub Discussion</li> </ul>"},{"location":"contact.html#issues-contributions","title":"\ud83d\udee0\ufe0f Issues &amp; Contributions","text":"<ul> <li>Open an Issue</li> <li>Submit a Pull Request</li> </ul>"},{"location":"contact.html#connect-with-me","title":"\ud83c\udf10 Connect with Me","text":"<ul> <li> GitHub</li> <li> X (Twitter)</li> <li> LinkedIn</li> <li> Instagram</li> </ul> <p>\ud83d\udcac Prefer email? Reach out via DM on LinkedIn or Twitter for contact info.</p>"},{"location":"frontend/index.html","title":"Frontend Development Overview","text":"<p>Frontend development focuses on the visual and interactive parts of a website or web application \u2014 what users see and interact with directly in their browser.</p>"},{"location":"frontend/index.html#core-responsibilities","title":"\ud83e\udde0 Core Responsibilities","text":"<ul> <li>UI/UX Implementation: Translating design mockups into working interfaces</li> <li>Interactivity: Handling user interactions like clicks, input, and navigation</li> <li>Performance Optimization: Ensuring fast load times and smooth experiences</li> <li>Responsiveness: Making interfaces work well across all devices and screen sizes</li> <li>Accessibility (a11y): Designing for inclusivity and usability by everyone</li> </ul>"},{"location":"frontend/index.html#core-technologies","title":"\ud83d\udee0\ufe0f Core Technologies","text":"Layer Technology Description Structure HTML Markup language that defines page structure Style CSS Styles layout, colors, and fonts Behavior JavaScript (JS) Adds interactivity and dynamic behavior"},{"location":"frontend/index.html#modern-frontend-stack","title":"\u2699\ufe0f Modern Frontend Stack","text":"<ul> <li>Frameworks: React, Vue.js, Angular, Svelte</li> <li>Styling: Tailwind CSS, Sass, CSS Modules, Styled Components</li> <li>Build Tools: Vite, Webpack, Parcel</li> <li>Package Managers: npm, yarn, pnpm</li> <li>Type Safety: TypeScript</li> <li>Testing: Jest, Vitest, Cypress, Playwright</li> <li>State Management: Redux, Zustand, Vuex, Recoil</li> </ul>"},{"location":"frontend/index.html#key-concepts","title":"\ud83e\udde9 Key Concepts","text":"<ul> <li>DOM Manipulation</li> <li>Event Handling</li> <li>Component-Based Architecture</li> <li>Routing &amp; Navigation</li> <li>API Integration (AJAX/Fetch/REST/GraphQL)</li> <li>Responsive Design &amp; Media Queries</li> <li>Cross-Browser Compatibility</li> <li>Progressive Enhancement &amp; Graceful Degradation</li> </ul>"},{"location":"frontend/index.html#security-best-practices","title":"\ud83d\udd10 Security Best Practices","text":"<ul> <li>Input validation &amp; sanitization</li> <li>Avoiding XSS and CSRF vulnerabilities</li> <li>Using HTTPS and secure cookies</li> </ul>"},{"location":"frontend/index.html#learning-resources","title":"\ud83d\udcda Learning Resources","text":"<ul> <li> <p>MDN Web Docs   The official and most comprehensive reference for HTML, CSS, and JavaScript.</p> </li> <li> <p>freeCodeCamp   100% free platform with interactive coding challenges, projects, and certifications.</p> </li> <li> <p>JavaScript.info   A modern deep dive into JavaScript with lots of practical examples.</p> </li> <li> <p>CSS-Tricks   Practical CSS tips, articles, and frontend-focused tutorials.</p> </li> <li> <p>W3Schools   Beginner-friendly tutorials and examples for HTML, CSS, and JS.</p> </li> <li> <p>The Odin Project   A full-stack curriculum with a strong frontend foundation and real-world projects.</p> </li> <li> <p>Codecademy   Interactive platform for learning frontend and full-stack development.</p> </li> <li> <p>SuperSimpleDev on YouTube   Friendly and beginner-oriented YouTube channel for HTML, CSS, and JavaScript.</p> </li> </ul>"},{"location":"frontend/index.html#frontend-video-tutorials-the-best-videos","title":"Frontend Video Tutorials (the best videos)","text":"<p>HTML &amp; CSS</p> <p>JavaScript</p> <p>Frontend development is where design meets code. It requires a balance of technical skill, creativity, and user empathy.</p>"},{"location":"frontend/js/index.html","title":"JavaScript Overview","text":"<p>This guide gives you a clear and easy-to-understand overview of JavaScript \u2014 from what it is to what it can do.</p>"},{"location":"frontend/js/index.html#1-what-is-javascript","title":"1. What is JavaScript?","text":"<p>JavaScript (JS) is a popular programming language used to make websites interactive. Along with HTML and CSS, it\u2019s one of the main tools used to build web pages.</p>"},{"location":"frontend/js/index.html#2-why-javascript-is-useful","title":"2. Why JavaScript is Useful","text":"<ul> <li>Runs in Your Browser: JavaScript lets websites respond to what you do \u2014 like clicking a button, typing in a form, or moving your mouse.</li> <li>Works Everywhere: It\u2019s not just for websites! You can use JavaScript to:</li> <li>Build web servers (with Node.js)</li> <li>Create mobile apps (with React Native)</li> <li>Make desktop apps (with Electron)</li> </ul>"},{"location":"frontend/js/index.html#3-key-features","title":"3. Key Features","text":"<ul> <li>No Need to Declare Types: You can write <code>let x = 5;</code> and later change it to <code>x = \"hello\";</code>. JavaScript won\u2019t complain!</li> <li>Functions are Flexible: You can treat functions like values \u2014 pass them around, return them from other functions, and store them in variables.</li> <li>Objects Inherit from Objects: Instead of using classes like in other languages, JavaScript uses something called prototypes. (Don't worry \u2014 ES6 added classes to make it easier!)</li> <li>Great at Handling Events: JavaScript is designed to deal with things happening on the page \u2014 like clicks, typing, or loading data from a server \u2014 without freezing or slowing down.</li> </ul>"},{"location":"frontend/js/index.html#4-ecmascript-es-the-standard","title":"4. ECMAScript (ES) - The Standard","text":"<p>JavaScript is based on a set of rules called ECMAScript. New versions (like ES6, ES7, etc.) add cool new features to make coding easier and more powerful.</p>"},{"location":"frontend/js/Basics.html","title":"JavaScript Basics","text":"<p>This guide covers the core building blocks of JavaScript \u2014 perfect for beginners!</p>"},{"location":"frontend/js/Basics.html#1-variables","title":"1. Variables","text":"<p>Variables store data.</p> <pre><code>let name = \"Alice\"; // Can change\nconst age = 25; // Can't change\nvar city = \"London\"; // Old way (not recommended)\n</code></pre> <ul> <li><code>let</code> and <code>const</code> are the modern way to create variables.</li> <li>Use <code>const</code> by default, unless you need to change the value.</li> </ul>"},{"location":"frontend/js/Basics.html#2-data-types","title":"2. Data Types","text":"<p>JavaScript has different types of data:</p> <pre><code>let text = \"hello\"; // String\nlet number = 42; // Number\nlet isHappy = true; // Boolean\nlet nothing = null; // Null\nlet notSet; // Undefined\nlet person = { name: \"Tom\" }; // Object\nlet list = [1, 2, 3]; // Array\n</code></pre>"},{"location":"frontend/js/Basics.html#3-operators","title":"3. Operators","text":"<pre><code>// Arithmetic\n5 + 3; // 8\n10 - 4; // 6\n6 * 2; // 12\n9 / 3; // 3\n\n// Comparison\n5 == \"5\"; // true (loose)\n5 === \"5\"; // false (strict)\n4 !== 5; // true\n\n// Logical\ntrue &amp;&amp; false; // false\ntrue || false; // true\n!true; // false\n</code></pre>"},{"location":"frontend/js/Basics.html#4-functions","title":"4. Functions","text":"<p>Functions are blocks of code you can reuse.</p> <pre><code>function greet(name) {\n  return \"Hello, \" + name;\n}\n\nconst sayHi = (name) =&gt; \"Hi, \" + name;\n\ngreet(\"Alice\"); // \"Hello, Alice\"\n</code></pre>"},{"location":"frontend/js/Basics.html#5-conditionals","title":"5. Conditionals","text":"<p>Run code based on conditions.</p> <pre><code>let age = 18;\n\nif (age &gt;= 18) {\n  console.log(\"You're an adult\");\n} else {\n  console.log(\"You're a minor\");\n}\n</code></pre>"},{"location":"frontend/js/Basics.html#6-loops","title":"6. Loops","text":"<p>Repeat code multiple times.</p> <pre><code>// For loop\nfor (let i = 0; i &lt; 5; i++) {\n  console.log(i);\n}\n\n// While loop\nlet i = 0;\nwhile (i &lt; 5) {\n  console.log(i);\n  i++;\n}\n</code></pre>"},{"location":"frontend/js/Basics.html#7-arrays","title":"7. Arrays","text":"<p>Store multiple values.</p> <pre><code>let fruits = [\"apple\", \"banana\", \"cherry\"];\nconsole.log(fruits[0]); // \"apple\"\nfruits.push(\"orange\"); // Add to end\n</code></pre>"},{"location":"frontend/js/Basics.html#8-objects","title":"8. Objects","text":"<p>Group related data together.</p> <pre><code>let person = {\n  name: \"Bob\",\n  age: 30,\n  isStudent: false,\n};\n\nconsole.log(person.name); // \"Bob\"\n</code></pre>"},{"location":"frontend/js/Basics.html#9-events","title":"9. Events","text":"<p>React to things like clicks.</p> <pre><code>&lt;button onclick=\"sayHello()\"&gt;Click me&lt;/button&gt;\n\n&lt;script&gt;\n  function sayHello() {\n    alert(\"Hello!\");\n  }\n&lt;/script&gt;\n</code></pre>"},{"location":"frontend/js/Basics.html#10-dom-manipulation","title":"10. DOM Manipulation","text":"<p>Change the web page with JavaScript.</p> <pre><code>&lt;p id=\"demo\"&gt;Hello&lt;/p&gt;\n\n&lt;script&gt;\n  document.getElementById(\"demo\").textContent = \"Changed!\";\n&lt;/script&gt;\n</code></pre>"},{"location":"frontend/js/Basics.html#11-asynchronous-code","title":"11. Asynchronous Code","text":"<p>Wait for things like data from a server.</p> <pre><code>// Using Promises\nfetch(\"https://api.example.com\")\n  .then((response) =&gt; response.json())\n  .then((data) =&gt; console.log(data));\n\n// Using async/await\nasync function getData() {\n  const response = await fetch(\"https://api.example.com\");\n  const data = await response.json();\n  console.log(data);\n}\n</code></pre>"},{"location":"frontend/js/Basics.html#summary","title":"Summary","text":"<p>JavaScript helps you make websites interactive. Learn these basics well:</p> <ul> <li>Variables &amp; Data Types</li> <li>Functions &amp; Loops</li> <li>Conditions &amp; Operators</li> <li>Arrays &amp; Objects</li> <li>DOM &amp; Events</li> <li>Async code</li> </ul> <p>Once you're comfortable, explore more advanced stuff like ES6+, modules, and frameworks (React, Vue, etc.).</p>"},{"location":"frontend/js/ES6.html","title":"ES6 Features","text":""},{"location":"frontend/js/ES6.html#1-let-and-const","title":"1. let and const","text":"<pre><code>let x = 10;\nconst y = 20;\n</code></pre>"},{"location":"frontend/js/ES6.html#2-arrow-functions","title":"2. Arrow Functions","text":"<pre><code>const greet = (name) =&gt; `Hello, ${name}`;\n</code></pre>"},{"location":"frontend/js/ES6.html#3-template-literals","title":"3. Template Literals","text":"<pre><code>let name = \"Alice\";\nconsole.log(`Hi, ${name}!`);\n</code></pre>"},{"location":"frontend/js/ES6.html#4-destructuring","title":"4. Destructuring","text":"<pre><code>const user = { name: \"Bob\", age: 25 };\nconst { name, age } = user;\n</code></pre>"},{"location":"frontend/js/ES6.html#5-spread-and-rest","title":"5. Spread and Rest","text":"<pre><code>// Spread\nlet nums = [1, 2, 3];\nlet copy = [...nums];\n\n// Rest\nfunction sum(...args) {\n  return args.reduce((a, b) =&gt; a + b);\n}\n</code></pre>"},{"location":"frontend/js/ES6.html#6-default-parameters","title":"6. Default Parameters","text":"<pre><code>function greet(name = \"Guest\") {\n  return `Hi, ${name}`;\n}\n</code></pre>"},{"location":"frontend/js/ES6.html#7-classes","title":"7. Classes","text":"<pre><code>class Person {\n  constructor(name) {\n    this.name = name;\n  }\n\n  greet() {\n    return `Hi, I'm ${this.name}`;\n  }\n}\n</code></pre>"},{"location":"frontend/js/ES6.html#8-promises","title":"8. Promises","text":"<p>Covered in detail in the Promises file.</p>"},{"location":"frontend/js/ErrorHandling.html","title":"Practical JavaScript Error Handling","text":"<p>A focused guide on modern error handling in JavaScript \u2014 how to use <code>try...catch</code>, custom errors, and ensure your code is stable in real-world scenarios.</p>"},{"location":"frontend/js/ErrorHandling.html#1-trycatch","title":"1. try...catch","text":""},{"location":"frontend/js/ErrorHandling.html#11-basic-syntax","title":"1.1 Basic Syntax","text":"<pre><code>try {\n  // Code that might throw an error\n} catch (error) {\n  // Code to handle the error\n}\n</code></pre>"},{"location":"frontend/js/ErrorHandling.html#12-example","title":"1.2 Example","text":"<pre><code>try {\n  let data = JSON.parse('{\"name\": \"Alice\"}');\n  console.log(data.name); // Alice\n} catch (err) {\n  console.error(\"Invalid JSON!\", err.message);\n}\n</code></pre>"},{"location":"frontend/js/ErrorHandling.html#2-what-triggers-catch","title":"2. What Triggers catch?","text":"<ul> <li>\u274c Syntax errors outside the try block are not caught.</li> <li>\u2705 Runtime errors inside the try block are caught.</li> </ul> <pre><code>try {\n  let result = riskyFunction();\n} catch (err) {\n  console.error(\"Something went wrong:\", err);\n}\n</code></pre>"},{"location":"frontend/js/ErrorHandling.html#3-finally-block","title":"3. finally Block","text":"<p>Always runs \u2014 whether there's an error or not. Use it for cleanup.</p> <pre><code>try {\n  console.log(\"Trying...\");\n  throw new Error(\"Oops!\");\n} catch (err) {\n  console.error(\"Caught:\", err.message);\n} finally {\n  console.log(\"Cleanup done\");\n}\n</code></pre> <p>Output:</p> <pre><code>Trying...\nCaught: Oops!\nCleanup done\n</code></pre>"},{"location":"frontend/js/ErrorHandling.html#4-throwing-custom-errors","title":"4. Throwing Custom Errors","text":""},{"location":"frontend/js/ErrorHandling.html#41-manually-throw","title":"4.1 Manually Throw","text":"<pre><code>function divide(a, b) {\n  if (b === 0) {\n    throw new Error(\"Cannot divide by zero\");\n  }\n  return a / b;\n}\n\ntry {\n  divide(4, 0);\n} catch (e) {\n  console.error(e.message); // \"Cannot divide by zero\"\n}\n</code></pre>"},{"location":"frontend/js/ErrorHandling.html#5-best-practices","title":"5. Best Practices","text":"<ul> <li>\u2705 Use <code>try...catch</code> for:</li> <li>JSON parsing</li> <li>Network/API calls</li> <li>Code that uses 3rd-party libraries</li> <li>\u274c Don\u2019t swallow errors silently:</li> </ul> <pre><code>catch (e) {\n  // bad: nothing logged\n}\n</code></pre> <ul> <li>\u2705 Log or rethrow unknown errors for debugging.</li> <li>\u2705 Use custom error types to distinguish logic vs technical failures.</li> </ul>"},{"location":"frontend/js/ErrorHandling.html#summary","title":"Summary","text":"<p>Solid error handling makes your code:</p> <ul> <li>Stable</li> <li>Debuggable</li> <li>Ready for production</li> <li>Friendly to users</li> </ul> <p>Mastering <code>try...catch</code> gives you more control and trust over your apps.</p>"},{"location":"frontend/js/fetch.html","title":"Fetch API and Async/Await","text":""},{"location":"frontend/js/fetch.html#1-what-is-fetch","title":"1- What is Fetch?","text":"<p>The Fetch API lets you make network requests (like getting data from a server).</p> <pre><code>fetch(\"https://api.example.com/data\")\n  .then((response) =&gt; response.json())\n  .then((data) =&gt; console.log(data))\n  .catch((error) =&gt; console.error(error));\n</code></pre>"},{"location":"frontend/js/fetch.html#2-using-asyncawait","title":"2- Using async/await","text":"<pre><code>async function getData() {\n  try {\n    const response = await fetch(\"https://api.example.com/data\");\n    const data = await response.json();\n    console.log(data);\n  } catch (error) {\n    console.error(error);\n  }\n}\n</code></pre>"},{"location":"frontend/js/fetch.html#3-why-asyncawait","title":"3- Why async/await?","text":"<ul> <li>Makes code easier to read</li> <li>Acts like synchronous code but works asynchronously</li> </ul>"},{"location":"frontend/js/fetch.html#4-async-vs-sync","title":"4- Async vs Sync","text":"<p>Synchronous: Code runs line by line, waits for each step. Asynchronous: Code can move on without waiting (non-blocking).</p> <p>Example:</p> <pre><code>console.log(\"Start\");\n\nsetTimeout(() =&gt; {\n  console.log(\"This runs later\");\n}, 1000);\n\nconsole.log(\"End\");\n</code></pre> <p>1- console.log(\"Start\");</p> <ul> <li>This line is synchronous, so it runs immediately and prints: Start</li> </ul> <p>2- setTimeout(() =&gt; { console.log(\"This runs later\"); }, 1000);</p> <ul> <li>This is asynchronous. It tells the browser:</li> </ul> <p>\"Wait 1 second, then run this function.\" But it doesn\u2019t stop the rest of the code from running.It continues right away. So instead of waiting 1 second here, the browser sets a &gt;timer and moves on.</p> <p>3- console.log(\"End\");</p> <ul> <li>This line runs immediately after setting the timer, so it prints: End</li> </ul> <ul> <li>so final output</li> </ul> <pre><code>Start\nEnd\nThis runs later\n</code></pre>"},{"location":"frontend/js/important.html","title":"Practical Advanced JavaScript","text":"<p>A focused guide on essential advanced features used in modern web development. No fluff \u2014 just what you\u2019ll actually use in projects.</p>"},{"location":"frontend/js/important.html#1-logical-operators","title":"1. Logical Operators: <code>&amp;&amp;</code>, <code>||</code>, <code>??</code>","text":""},{"location":"frontend/js/important.html#11-and","title":"1.1 <code>&amp;&amp;</code> (AND)","text":"<p>Returns the first falsy or the last truthy value.</p> <pre><code>isLoggedIn &amp;&amp; showDashboard();\n</code></pre> <p>Use for: conditional execution.</p>"},{"location":"frontend/js/important.html#12-or","title":"1.2 <code>||</code> (OR)","text":"<p>Returns the first truthy value.</p> <pre><code>const name = inputName || \"Guest\";\n</code></pre> <p>Use for: setting fallback/default values.</p>"},{"location":"frontend/js/important.html#13-nullish-coalescing","title":"1.3 <code>??</code> (Nullish Coalescing)","text":"<p>Returns the right-hand value only if the left is null or undefined.</p> <pre><code>const title = post.title ?? \"Untitled\";\n</code></pre> <p>Use when empty strings or 0 are valid values.</p>"},{"location":"frontend/js/important.html#2-optional-chaining","title":"2. Optional Chaining ?.","text":"<p>Safe access to nested properties.</p> <pre><code>const city = user?.address?.city;\nconst result = callback?.(data);\n</code></pre>"},{"location":"frontend/js/important.html#3-ternary-operator","title":"3. Ternary Operator ?:","text":"<p>Shorthand for if-else.</p> <pre><code>const access = isAdmin ? \"Full\" : \"Limited\";\n</code></pre> <p>Can also be nested, but avoid deep nesting.</p>"},{"location":"frontend/js/important.html#4-short-circuit-evaluation","title":"4. Short-Circuit Evaluation","text":"<pre><code>const log = (msg) =&gt; console.log(msg);\nlet debug = true;\n\ndebug &amp;&amp; log(\"Debug mode on\"); // runs only if debug is true\n</code></pre>"},{"location":"frontend/js/important.html#5-array-methods-detailed","title":"5. Array Methods (Detailed)","text":""},{"location":"frontend/js/important.html#51-map-transform-each-element","title":"5.1 <code>.map()</code> \u2013 Transform Each Element","text":"<p>Purpose: Transforms each element of an array and returns a new array of the same length.</p> <pre><code>const numbers = [1, 2, 3];\nconst squares = numbers.map((x) =&gt; x * x);\nconsole.log(squares); // [1, 4, 9]\n</code></pre> <p>Use Case Examples:</p> <ul> <li>Convert values (e.g. Celsius to Fahrenheit)</li> <li>Extract fields from objects</li> <li>Reformat data</li> </ul> <pre><code>const users = [{ name: \"Alice\" }, { name: \"Bob\" }, { name: \"Charlie\" }];\n\nconst names = users.map((user) =&gt; user.name);\nconsole.log(names); // [\"Alice\", \"Bob\", \"Charlie\"]\n</code></pre>"},{"location":"frontend/js/important.html#52-filter-select-matching-elements","title":"5.2 <code>.filter()</code> \u2013 Select Matching Elements","text":"<p>Purpose: Returns a new array that contains only the elements that pass the truth test you provide.</p> <pre><code>const nums = [1, 2, 3, 4, 5, 6];\nconst even = nums.filter((n) =&gt; n % 2 === 0);\nconsole.log(even); // [2, 4, 6]\n</code></pre> <p>Use Case Examples:</p> <ul> <li>Filter by a condition (e.g. status === 'active')</li> <li>Remove falsy values</li> <li>Select items that match user input (search/filter)</li> </ul> <pre><code>const products = [\n  { name: \"Laptop\", inStock: true },\n  { name: \"Phone\", inStock: false },\n];\n\nconst available = products.filter((p) =&gt; p.inStock);\nconsole.log(available); // [{ name: \"Laptop\", inStock: true }]\n</code></pre>"},{"location":"frontend/js/important.html#53-reduce-accumulate-values","title":"5.3 <code>.reduce()</code> \u2013 Accumulate Values","text":"<p>Purpose: Iterates through the array and reduces it to a single value (e.g. sum, average, object).</p> <pre><code>const nums = [1, 2, 3, 4];\nconst total = nums.reduce((sum, n) =&gt; sum + n, 0);\nconsole.log(total); // 10\n</code></pre> <p>Syntax:</p> <pre><code>array.reduce((accumulator, currentValue) =&gt; {\n  return updatedAccumulator;\n}, initialValue);\n</code></pre> <p>Use Case Examples:</p> <ul> <li>Sum or average numbers</li> <li>Count occurrences</li> <li>Group items by key</li> <li>Flatten arrays</li> </ul> <pre><code>const votes = [\"yes\", \"no\", \"yes\", \"yes\"];\nconst count = votes.reduce((acc, vote) =&gt; {\n  acc[vote] = (acc[vote] || 0) + 1;\n  return acc;\n}, {});\n\nconsole.log(count); // { yes: 3, no: 1 }\n</code></pre>"},{"location":"frontend/js/important.html#when-to-use-each","title":"When to Use Each","text":"Method Purpose Returns Common Use <code>.map()</code> Transform every element New array Format, extract, modify <code>.filter()</code> Include elements matching a test Filtered array Search, conditionally display <code>.reduce()</code> Condense to one result Single value Total, summary, grouped object"},{"location":"frontend/js/important.html#summary","title":"Summary","text":"<p>These patterns make your code:</p> <ul> <li>Safer</li> <li>Shorter</li> <li>Easier to maintain</li> <li>Professional and ready for real-world use</li> </ul> <p>Master these and you'll be solid for frontend frameworks, Node.js, and API-based work.</p>"},{"location":"frontend/js/important2.html","title":"JavaScript Event Loop \ud83d\udd04","text":"<p>Understanding the event loop is crucial for writing efficient, non-blocking JavaScript \u2014 especially for frontend or Node.js applications.</p>"},{"location":"frontend/js/important2.html#1-javascript-runtime-model","title":"1. JavaScript Runtime Model","text":"<p>JavaScript is single-threaded, meaning it can do one thing at a time. But thanks to the event loop, it can handle asynchronous tasks like network requests, timers, and UI updates.</p>"},{"location":"frontend/js/important2.html#2-key-components","title":"2. Key Components","text":""},{"location":"frontend/js/important2.html#21-call-stack","title":"2.1 Call Stack","text":"<ul> <li>Keeps track of function calls</li> <li>Follows LIFO (Last-In, First-Out)</li> <li>If the stack is busy, JS can't do anything else</li> </ul> <pre><code>function greet() {\n  console.log(\"Hello\");\n}\n\ngreet(); // pushed to the stack, then popped after execution\n</code></pre>"},{"location":"frontend/js/important2.html#22-web-apis-browser-apis","title":"2.2 Web APIs / Browser APIs","text":"<p>Provided by the browser (or Node.js environment)</p> <p>Includes: setTimeout, DOM events, AJAX/fetch, etc.</p> <pre><code>setTimeout(() =&gt; {\n  console.log(\"Timeout!\");\n}, 0);\n</code></pre> <p>The setTimeout callback doesn't go to the call stack immediately. It waits in a queue.</p>"},{"location":"frontend/js/important2.html#23-callback-queue-task-queue","title":"2.3 Callback Queue (Task Queue)","text":"<ul> <li>Stores setTimeout, DOM events, etc.</li> <li>Waits for the call stack to be empty</li> <li>Then the event loop pushes tasks to the call stack</li> </ul>"},{"location":"frontend/js/important2.html#24-microtask-queue","title":"2.4 Microtask Queue","text":"<ul> <li>Stores Promise callbacks, queueMicrotask, MutationObserver</li> <li>Runs before the callback queue after each task</li> </ul> <pre><code>Promise.resolve().then(() =&gt; {\n  console.log(\"Promise resolved\");\n});\n\nsetTimeout(() =&gt; {\n  console.log(\"Timeout\");\n}, 0);\n\n// Output:\n// \"Promise resolved\"\n// \"Timeout\"\n</code></pre>"},{"location":"frontend/js/important2.html#3-the-event-loop-in-action","title":"3. The Event Loop in Action","text":""},{"location":"frontend/js/important2.html#example","title":"Example","text":"<pre><code>console.log(\"Start\");\n\nsetTimeout(() =&gt; {\n  console.log(\"Timeout\");\n}, 0);\n\nPromise.resolve().then(() =&gt; {\n  console.log(\"Promise\");\n});\n\nconsole.log(\"End\");\n</code></pre>"},{"location":"frontend/js/important2.html#output","title":"Output:","text":"<pre><code>Start\nEnd\nPromise\nTimeout\n</code></pre> <p>Why?</p> <ul> <li>Call stack: \"Start\" and \"End\" run immediately.</li> <li>Promise goes to microtask queue \u2192 runs before setTimeout.</li> <li>setTimeout is in callback queue \u2192 runs last.</li> </ul>"},{"location":"frontend/js/important2.html#4-visualization","title":"4. Visualization","text":"<ul> <li>JS reads line by line \u2192 pushes function calls to the call stack</li> <li>Async tasks (like timers or fetch) are sent to Web APIs</li> <li>Their callbacks go to:</li> <li>Microtask Queue (Promises)</li> <li>Callback Queue (Timers, DOM events)</li> <li>The Event Loop checks:</li> <li>If the call stack is empty</li> <li>Runs all microtasks</li> <li>Then runs one callback from the callback queue</li> </ul>"},{"location":"frontend/js/important2.html#5-why-it-matters","title":"5. Why It Matters","text":"<ul> <li>Avoid blocking the call stack (e.g., with large loops or sync XHR)</li> <li>Always remember Promises resolve before timeouts</li> <li>Debug async behavior (e.g., race conditions, timing issues)</li> </ul>"},{"location":"frontend/js/important2.html#video-explanation","title":"Video Explanation","text":"<ul> <li>Here\u2019s a great video that visually explains the JavaScript Event Loop:</li> </ul> JavaScript Event Loop - Philip Roberts (JSConf)"},{"location":"frontend/js/important2.html#summary","title":"Summary","text":"<p>The event loop allows JS to handle:</p> <ul> <li>Multiple async tasks</li> <li>Promises and await</li> <li>Efficient and non-blocking code</li> </ul> <p>Mastering it helps you:</p> <ul> <li>Write better asynchronous logic</li> <li>Debug timing-related bugs</li> <li>Understand frameworks like React, Vue, and Node.js better</li> </ul>"},{"location":"frontend/js/promises.html","title":"JavaScript Promises","text":""},{"location":"frontend/js/promises.html#1-what-is-a-promise","title":"1- What is a Promise?","text":"<p>A Promise is an object that represents a task that might complete in the future.</p>"},{"location":"frontend/js/promises.html#2-states-of-a-promise","title":"2- States of a Promise","text":"<ul> <li>Pending: still waiting</li> <li>Fulfilled: completed successfully</li> <li>Rejected: failed</li> </ul>"},{"location":"frontend/js/promises.html#3-creating-a-promise","title":"3- Creating a Promise","text":"<pre><code>const promise = new Promise((resolve, reject) =&gt; {\n  let success = true;\n  if (success) {\n    resolve(\"It worked!\");\n  } else {\n    reject(\"It failed.\");\n  }\n});\n</code></pre>"},{"location":"frontend/js/promises.html#4-using-promises","title":"4- Using Promises","text":"<pre><code>promise\n  .then((result) =&gt; console.log(result))\n  .catch((error) =&gt; console.error(error));\n</code></pre>"},{"location":"frontend/js/promises.html#5-chaining-promises","title":"5- Chaining Promises","text":"<pre><code>fetch(\"https://api.example.com\")\n  .then((res) =&gt; res.json())\n  .then((data) =&gt; console.log(data))\n  .catch((err) =&gt; console.error(err));\n</code></pre>"},{"location":"frontend/js/dom/dom.html","title":"JavaScript DOM \ud83c\udf10","text":""},{"location":"frontend/js/dom/dom.html#1-what-is-the-dom","title":"1- What is the DOM?","text":"<p>The Document Object Model (DOM) is a tree-like structure that represents the HTML elements of a web page. JavaScript uses the DOM to read and change content, structure, and style.</p>"},{"location":"frontend/js/dom/dom.html#2-accessing-elements","title":"2- Accessing Elements","text":"<pre><code>document.getElementById(\"id\");\ndocument.getElementsByClassName(\"class\");\ndocument.getElementsByTagName(\"tag\");\ndocument.querySelector(\"selector\");\ndocument.querySelectorAll(\"selector\");\n</code></pre>"},{"location":"frontend/js/dom/dom.html#3-changing-content","title":"3- Changing Content","text":"<pre><code>document.getElementById(\"demo\").textContent = \"Hello!\";\ndocument.getElementById(\"demo\").innerHTML = \"&lt;b&gt;Hello!&lt;/b&gt;\";\n</code></pre>"},{"location":"frontend/js/dom/dom.html#4-changing-styles","title":"4- Changing Styles","text":"<pre><code>document.getElementById(\"demo\").style.color = \"red\";\n</code></pre>"},{"location":"frontend/js/dom/dom.html#5-creating-and-adding-elements","title":"5- Creating and Adding Elements","text":"<pre><code>const p = document.createElement(\"p\");\np.textContent = \"New paragraph\";\ndocument.body.appendChild(p);\n</code></pre>"},{"location":"frontend/js/dom/dom.html#6-removing-elements","title":"6- Removing Elements","text":"<pre><code>const elem = document.getElementById(\"demo\");\nelem.remove();\n</code></pre>"},{"location":"frontend/js/dom/dom.html#7-dom-events","title":"7- DOM Events","text":"<pre><code>document.getElementById(\"btn\").addEventListener(\"click\", function () {\n  alert(\"Clicked!\");\n});\n</code></pre>"},{"location":"frontend/js/dom/eventHandler.html","title":"JavaScript Events","text":""},{"location":"frontend/js/dom/eventHandler.html#1-what-is-an-event","title":"1- What is an Event?","text":"<p>An event is something that happens in the browser (click, scroll, key press, etc.).</p>"},{"location":"frontend/js/dom/eventHandler.html#2-common-event-types","title":"2- Common Event Types","text":"<ul> <li><code>click</code></li> <li><code>mouseover</code></li> <li><code>keydown</code></li> <li><code>submit</code></li> <li><code>load</code></li> </ul>"},{"location":"frontend/js/dom/eventHandler.html#3-adding-event-listeners","title":"3- Adding Event Listeners","text":"<pre><code>document.getElementById(\"btn\").addEventListener(\"click\", function () {\n  alert(\"Button clicked!\");\n});\n</code></pre>"},{"location":"frontend/js/dom/eventHandler.html#4-removing-event-listeners","title":"4- Removing Event Listeners","text":"<pre><code>function sayHi() {\n  alert(\"Hi\");\n}\nconst btn = document.getElementById(\"btn\");\nbtn.addEventListener(\"click\", sayHi);\nbtn.removeEventListener(\"click\", sayHi);\n</code></pre>"},{"location":"frontend/js/dom/eventHandler.html#5-event-object","title":"5- Event Object","text":"<pre><code>document.addEventListener(\"click\", function (event) {\n  console.log(event.target); // What was clicked\n});\n</code></pre>"},{"location":"frontend/js/dom/eventHandler.html#6-event-bubbling-and-capturing","title":"6- Event Bubbling and Capturing","text":"<ul> <li>Bubbling: Events go from the innermost element up.</li> <li>Capturing: Events go from the outermost element down.</li> </ul>"}]}